import{_ as a,c as e,o as t,d as m}from"./plugin-vue_export-helper.bd4ff235.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 25-26","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 25-26","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-26T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/25-26.md","lastUpdated":1626206087000}',i={},o=m('<div class="stanza"><a href="#s3.25" id="s3.25" class="num">3.25</a><div class="sans"><p>\u0907\u0924\u094D\u0925\u092E\u093E\u0938\u093E\u0926\u093F\u0924\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u094B \u092F\u094B\u0917\u0940\u2014</p><blockquote><p><strong>\u0936\u093F\u0935\u0924\u0941\u0932\u094D\u092F\u094B \u091C\u093E\u092F\u0924\u0947\u0965\u0968\u096B\u0965</strong></p></blockquote><p>\u0924\u0941\u0930\u094D\u092F\u092A\u0930\u093F\u0936\u0940\u0932\u0928\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u093E\u0924\u094D\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0924\u0941\u0930\u094D\u092F\u093E\u0924\u0940\u0924\u092A\u0926\u0903 \u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u0938\u094D\u0935\u091A\u094D\u091B\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0918\u0928\u0947\u0928 \u0936\u093F\u0935\u0947\u0928 \u092D\u0917\u0935\u0924\u093E \u0924\u0941\u0932\u094D\u092F\u094B \u0926\u0947\u0939\u0915\u0932\u093E\u092F\u093E \u0905\u0935\u093F\u0917\u0932\u0928\u093E\u0924\u094D\u0924\u0924\u094D\u0938\u092E\u094B \u091C\u093E\u092F\u0924\u0947\u0964 \u0924\u0926\u094D\u0935\u093F\u0917\u0932\u0928\u0947\u0928 \u0938\u093E\u0915\u094D\u0937\u093E\u091A\u094D\u091B\u093F\u0935 \u090F\u0935\u093E\u0938\u093E\u0935\u093F\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0924\u0925\u093E \u091A \u0936\u094D\u0930\u0940\u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u0947</p><blockquote><p>\u0924\u0938\u094D\u092E\u093E\u0928\u094D\u0928\u093F\u0924\u094D\u092F\u092E\u0938\u0928\u094D\u0926\u093F\u0917\u094D\u0927\u0902 \u092C\u0941\u0926\u094D\u0927\u094D\u0935\u093E \u092F\u094B\u0917\u0902 \u0917\u0941\u0930\u094B\u0930\u094D\u092E\u0941\u0916\u093E\u0924\u094D\u0964<br> \u0905\u0935\u093F\u0915\u0932\u094D\u092A\u0947\u0928 \u092D\u093E\u0935\u0947\u0928 \u092D\u093E\u0935\u092F\u0947\u0924\u094D\u0924\u0928\u094D\u092E\u092F\u0924\u094D\u0935\u0924\u0903\u0965<br> \u092F\u093E\u0935\u0924\u094D\u0924\u0924\u094D\u0938\u092E\u0924\u093E\u0902 \u092F\u093E\u0924\u093F \u092D\u0917\u0935\u093E\u0928\u094D\u092D\u0948\u0930\u0935\u094B\u093D\u092C\u094D\u0930\u0935\u0940\u0924\u094D\u0964</p></blockquote><p>\u0907\u0924\u093F\u0965\u0968\u096B\u0965</p></div><hr><div class="trans"><p>Ittham\u0101s\u0101ditaprakar\u1E63o yog\u012B\u2014</p><blockquote><p><strong>\u015Aivatulyo j\u0101yate||25||</strong></p></blockquote><p>Turyapari\u015B\u012Blanaprakar\u1E63\u0101tpr\u0101ptatury\u0101t\u012Btapada\u1E25 parip\u016Br\u1E47asvacchasvacchandacid\u0101nandaghanena \u015Bivena bhagavat\u0101 tulyo dehakal\u0101y\u0101 avigalan\u0101ttatsamo j\u0101yate| Tadvigalanena s\u0101k\u1E63\u0101cchiva ev\u0101s\u0101vityartha\u1E25| Tath\u0101 ca \u015Br\u012Bk\u0101lik\u0101krame</p><blockquote><p>Tasm\u0101nnityamasandigdha\u1E41 buddhv\u0101 yoga\u1E41 gurormukh\u0101t|<br> Avikalpena bh\u0101vena bh\u0101vayettanmayatvata\u1E25||<br> Y\u0101vattatsamat\u0101\u1E41 y\u0101ti bhagav\u0101nbhairavo&#39;brav\u012Bt|</p></blockquote><p>iti||25||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham)</em>, Yog\u012B <em>(yog\u012B)</em> \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0431\u0438\u043B\u0441\u044F <em>(\u0101s\u0101dita)</em> \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u0430 \u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430 <em>(prakar\u1E63a\u1E25)</em>\u2014</p><blockquote><p><strong>[\u042D\u0442\u043E\u0442 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 Yog\u012B, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u0439 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F], \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(j\u0101yate)</em> \u0440\u0430\u0432\u043D\u044B\u043C <em>(tulya\u1E25)</em> \u015Aiva <em>(\u015Biva)</em>||25||</strong></p></blockquote><p>\u0427\u0435\u0440\u0435\u0437 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u044C <em>(prakar\u1E63\u0101t)</em> \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u0430 <em>(pari\u015B\u012Blana)</em> \u0441 Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(turya)</em>, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pr\u0101pta... pada\u1E25)</em> Tury\u0101t\u012Bta --\u0442.\u0435. \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 Turya-- <em>(turya-at\u012Bta)</em> [\u0438] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(j\u0101yate)</em> \u0440\u0430\u0432\u043D\u044B\u043C <em>(tulya\u1E25)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u0438 \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 <em>(bhagavat\u0101)</em> \u015Aiva <em>(\u015Bivena)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E <em>(parip\u016Br\u1E47a)</em> \u044F\u0441\u043D\u043E\u0439 <em>(svaccha)</em> [\u0438] \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0439 <em>(svacchanda)</em> \u043C\u0430\u0441\u0441\u043E\u0439 <em>(ghanena)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> [\u0438] \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em>; [\u0438] \u0434\u043E \u0442\u0435\u0445 \u043F\u043E\u0440, \u043F\u043E\u043A\u0430 \u0442\u0435\u043B\u0435\u0441\u043D\u044B\u0439 \u0430\u0441\u043F\u0435\u043A\u0442 <em>(deha-kal\u0101y\u0101)</em> \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(avigalan\u0101t)</em> --\u043F\u043E\u043A\u0430 \u043E\u043D \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0436\u0438\u0432\u044B\u043C--, [\u0442\u0430\u043A\u043E\u0439 Yog\u012B] <em>(j\u0101yate)</em> \u043F\u043E\u0434\u043E\u0431\u0435\u043D <em>(sama\u1E25)</em> \u0415\u043C\u0443 <em>(tad)</em>|</p><p>\u041F\u043E\u0441\u043B\u0435 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(vigalanena)</em> \u0442\u043E\u0433\u043E --\u0442\u0435\u043B\u0430 \u043F\u043E\u0441\u043B\u0435 \u0441\u043C\u0435\u0440\u0442\u0438-- <em>(tad)</em>, \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(asau)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0421\u0430\u043C\u0438\u043C \u015Aiva <em>(\u015Biva\u1E25 eva)</em> \u043B\u0438\u0447\u043D\u043E <em>(s\u0101k\u1E63\u0101t)</em>|</p><p>[\u0411\u044B\u043B\u043E] \u0442\u0430\u043A <em>(tath\u0101 ca)</em> [\u0441\u043A\u0430\u0437\u0430\u043D\u043E] \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C K\u0101lik\u0101krama <em>(\u015Br\u012B-k\u0101lik\u0101krame)</em> [\u0442\u0430\u043A\u0436\u0435]:</p><blockquote><p>&quot;\u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u044B\u0439 <em>(bhagav\u0101n)</em> Bhairava --\u0442.\u0435. \u0412\u044B\u0441\u0448\u0438\u0439 \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C-- <em>(bhairava\u1E25)</em> \u0441\u043A\u0430\u0437\u0430\u043B <em>(abrav\u012Bt)</em>: &#39;\u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tasm\u0101t)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> \u043E\u0431\u043B\u0430\u0434\u0430\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435\u043C <em>(buddhv\u0101)</em> [\u0438] \u0431\u0435\u0437 \u0432\u0441\u044F\u043A\u0438\u0445 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(asandigdham)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F [\u0441 \u015Aiva] <em>(yogam)</em>, (\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445) \u0438\u0437 \u0443\u0441\u0442 <em>(mukh\u0101t)</em> guru --\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0443\u0447\u0438\u0442\u0435\u043B\u044F-- <em>(guro\u1E25)</em>, \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C [ \u015Aiva] <em>(bh\u0101vayet)</em> \u0431\u0435\u0437 \u043C\u044B\u0441\u043B\u0435\u0439 <em>(avikalpena)</em>, \u0441 \u044D\u043C\u043E\u0446\u0438\u0435\u0439 --\u0441 \u0447\u0443\u0432\u0441\u0442\u0432\u043E\u043C-- <em>(bh\u0101vena)</em><sup>1</sup> [\u0438] \u0441 \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0435\u043C \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F <em>(mayatvata\u1E25)</em> \u0441 \u041D\u0438\u043C <em>(tad)</em>, \u043F\u043E\u043A\u0430 <em>(y\u0101vat)</em> \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 <em>(y\u0101ti)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0438\u043B\u0438 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0430 <em>(samat\u0101m)</em> \u0441 \u041D\u0438\u043C <em>(tad... iti)</em>&#39;&quot;|</p></blockquote><p>||25||</p><hr><ol><li>&quot;Avikalpena bh\u0101vena&quot; \u043D\u0435\u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043E \u043A\u0430\u043A &quot;\u0441 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F \u043C\u044B\u0441\u043B\u0435\u0439&quot;, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0441\u043B\u043E\u0432\u043E &quot;bh\u0101va&quot;, \u043F\u043E\u043C\u0438\u043C\u043E&quot;\u0447\u0443\u0432\u0441\u0442\u0432\u043E, \u044D\u043C\u043E\u0446\u0438\u044F&quot; \u0438 \u0434\u0440\u0443\u0433\u043E\u0439 \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0439 \u043A\u0443\u0447\u0438 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0443\u0441\u043B\u043E\u0432\u0438\u0435&quot;. OK, \u044F \u043F\u0440\u043E\u0441\u0442\u043E \u0445\u043E\u0442\u0435\u043B \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442.</li></ol></div><div class="stanza"><a href="#s3.26" id="s3.26" class="num">3.26</a><div class="sans"><p>\u090F\u0935\u092E\u092A\u093F \u091A \u092F\u0947\u0928\u0947\u0926\u0902 \u0924\u0926\u094D\u0927\u093F \u092D\u094B\u0917\u0924 \u0907\u0924\u094D\u092F\u093E\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u0930\u0940\u0924\u094D\u092F\u093E \u0909\u092A\u0928\u0924\u092D\u094B\u0917\u093E\u0924\u093F\u0935\u093E\u0939\u0928\u092E\u093E\u0924\u094D\u0930\u092A\u094D\u0930\u092F\u094B\u091C\u0928\u093E\u0926\u094D\u0926\u0947\u0939\u0938\u094D\u0925\u093F\u0924\u093F\u0930\u0938\u094D\u092F \u0928\u093E\u0924\u093F\u0915\u094D\u0930\u092E\u0923\u0940\u092F\u0947\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0936\u0930\u0940\u0930\u0935\u0943\u0924\u094D\u0924\u093F\u0930\u094D\u0935\u094D\u0930\u0924\u092E\u094D\u0965\u0968\u096C\u0965</strong></p></blockquote><p>\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0926\u0943\u0936\u093E \u0936\u093F\u0935\u0924\u0941\u0932\u094D\u092F\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903 \u0936\u093F\u0935\u093E\u0939\u092E\u094D\u092D\u093E\u0935\u0947\u0928 \u0935\u0930\u094D\u0924\u092E\u093E\u0928\u0938\u094D\u092F \u0936\u0930\u0940\u0930\u0947 \u0935\u0943\u0924\u094D\u0924\u093F\u0930\u094D\u0935\u0930\u094D\u0924\u0928\u0902 \u092F\u0924\u094D \u0924\u0926\u0947\u0935 \u0935\u094D\u0930\u0924\u0902 \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0924\u094D\u092E\u0915\u0928\u093F\u0924\u094D\u092F\u094B\u0926\u093F\u0924\u092A\u0930\u092A\u0942\u091C\u093E\u0924\u0924\u094D\u092A\u0930\u0938\u094D\u092F \u0928\u093F\u092F\u092E\u0947\u0928\u093E\u0928\u0941\u0937\u094D\u0920\u0947\u092F\u092E\u0938\u094D\u092F\u0964 \u0924\u0925\u093E \u091A \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u0941\u092A\u094D\u0930\u0926\u0940\u092A\u094D\u0924\u0947 \u092F\u0925\u093E \u0935\u0939\u094D\u0928\u094C \u0936\u093F\u0916\u093E \u0926\u0943\u0936\u094D\u092F\u0947\u0924 \u091A\u093E\u092E\u094D\u092C\u0930\u0947\u0964<br> \u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u0938\u094D\u0925\u093F\u0924\u094B \u0939\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u0924\u0926\u094D\u0935\u0932\u094D\u0932\u0940\u092F\u0947\u0924 \u0924\u0924\u094D\u092A\u0926\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u094D\u092F\u0935\u0938\u094D\u0925\u093F\u0924\u0938\u094D\u092F\u0948\u0935 \u0936\u093F\u0935\u0938\u092E\u093E\u0935\u093F\u0937\u094D\u091F\u0924\u094D\u0935\u092E\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u0928 \u092A\u0941\u0928\u0938\u094D\u0924\u0938\u094D\u092F \u0926\u0947\u0939\u0938\u094D\u0925\u093F\u0924\u093F\u0935\u094D\u092F\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u0902 \u0935\u094D\u0930\u0924\u092E\u0941\u092A\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u094D\u0930\u093F\u0915\u0938\u093E\u0930\u0947</p><blockquote><p>\u0926\u0947\u0939\u094B\u0924\u094D\u0925\u093F\u0924\u093E\u092D\u093F\u0930\u094D\u092E\u0941\u0926\u094D\u0930\u093E\u092D\u093F\u0930\u094D\u092F\u0903 \u0938\u0926\u093E \u092E\u0941\u0926\u094D\u0930\u093F\u0924\u094B \u092C\u0941\u0927\u0903\u0964<br> \u0938 \u0924\u0941 \u092E\u0941\u0926\u094D\u0930\u093E\u0927\u0930\u0903 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0903 \u0936\u0947\u0937\u093E \u0935\u093E \u0905\u0938\u094D\u0925\u093F\u0927\u093E\u0930\u0915\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0915\u0941\u0932\u092A\u091E\u094D\u091A\u093E\u0936\u093F\u0915\u093E\u092F\u093E\u092E\u092A\u093F</p><blockquote><p>\u0905\u0935\u094D\u092F\u0915\u094D\u0924\u0932\u093F\u0919\u094D\u0917\u093F\u0928\u0902 \u0926\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u0938\u092E\u094D\u092D\u093E\u0937\u0928\u094D\u0924\u0947 \u092E\u0930\u0940\u091A\u092F\u0903\u0964<br> \u0932\u093F\u0919\u094D\u0917\u093F\u0928\u0902 \u0928\u094B\u092A\u0938\u0930\u094D\u092A\u0928\u094D\u0924\u094D\u092F\u0924\u093F\u0917\u0941\u092A\u094D\u0924\u0924\u0930\u093E \u092F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0968\u096C\u0965</p></div><hr><div class="trans"><p>Evamapi ca yeneda\u1E41 taddhi bhogata ity\u0101dyuktar\u012Bty\u0101 upanatabhog\u0101tiv\u0101hanam\u0101traprayojan\u0101ddehasthitirasya n\u0101tikrama\u1E47\u012Byety\u0101ha\u2014</p><blockquote><p><strong>\u015Aar\u012Brav\u1E5Bttirvratam||26||</strong></p></blockquote><p>Proktad\u1E5B\u015B\u0101 \u015Bivatulyasya yogina\u1E25 \u015Biv\u0101hambh\u0101vena vartam\u0101nasya \u015Bar\u012Bre v\u1E5Bttirvartana\u1E41 yat tadeva vrata\u1E41 svasvar\u016Bpavimar\u015B\u0101tmakanityoditaparap\u016Bj\u0101tatparasya niyamen\u0101nu\u1E63\u1E6Dheyamasya| Tath\u0101 ca \u015Br\u012Bsvacchande</p><blockquote><p>Suprad\u012Bpte yath\u0101 vahnau \u015Bikh\u0101 d\u1E5B\u015Byeta c\u0101mbare|<br> Dehapr\u0101\u1E47asthito hy\u0101tm\u0101 tadvall\u012Byeta tatpade||</p></blockquote><p>ityukty\u0101 dehapr\u0101\u1E47\u0101dyavasthitasyaiva \u015Bivasam\u0101vi\u1E63\u1E6Datvamuktam| Na punastasya dehasthitivyatirikta\u1E41 vratamupayuktam| Yadukta\u1E41 \u015Br\u012Btrikas\u0101re</p><blockquote><p>Dehotthit\u0101bhirmudr\u0101bhirya\u1E25 sad\u0101 mudrito budha\u1E25|<br> Sa tu mudr\u0101dhara\u1E25 prokta\u1E25 \u015Be\u1E63\u0101 v\u0101 asthidh\u0101rak\u0101\u1E25||</p></blockquote><p>iti| \u015Ar\u012Bkulapa\xF1c\u0101\u015Bik\u0101y\u0101mapi</p><blockquote><p>Avyaktali\u1E45gina\u1E41 d\u1E5B\u1E63\u1E6Dv\u0101 sambh\u0101\u1E63ante mar\u012Bcaya\u1E25|<br> Li\u1E45gina\u1E41 nopasarpantyatiguptatar\u0101 yata\u1E25||</p></blockquote><p>iti||26||</p></div><hr><p>\u0418 <em>(ca)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> --\u0442.\u0435. \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433 \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C--, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u0435\u0442\u043E\u0434\u0443 <em>(r\u012Bty\u0101)</em>, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u043C\u0443 <em>(ukta)</em> [\u0432 \u041F\u0438\u0441\u0430\u043D\u0438\u0438], \u0430 \u0438\u043C\u0435\u043D\u043D\u043E &quot;\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yena)</em> [\u0438\u043C\u0435\u0435\u0442\u0441\u044F] \u044D\u0442\u043E [\u0442\u0435\u043B\u043E] <em>(idam)</em>, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tad hi)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C bhoga, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(bhogata\u1E25)</em> \u0438 \u0442.\u043F. <em>(iti \u0101di)</em>&quot;, \u0442\u0430\u043A \u043A\u0430\u043A [\u043F\u043E\u043A\u0430 \u0442\u0435\u043B\u043E \u0436\u0438\u0432\u0435\u0442,] \u0446\u0435\u043B\u044C <em>(prayojan\u0101t)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 <em>(m\u0101tra)</em> \u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u0438\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0432\u044B\u043F\u0430\u0434\u0430\u0442\u044C \u043D\u0430 \u0435\u0433\u043E \u0434\u043E\u043B\u044E <em>(upanata-bhoga-ativ\u0101hana)</em><sup>1</sup>, \u043D\u0435 <em>(na)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0435\u043D\u0435\u0431\u0440\u0435\u0433\u0430\u0442\u044C <em>(atikrama\u1E47\u012By\u0101)</em> \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0435\u043D\u0438\u0435\u043C (\u0436\u0438\u0437\u043D\u0438) <em>(sthiti\u1E25)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em> \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>. [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em> \u0442\u0430\u043A <em>(iti)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435]\u2014</p><blockquote><p><strong>\u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 <em>(v\u1E5Btti\u1E25)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(\u015Bar\u012Bra)</em> [\u2014 \u044D\u0442\u043E \u0435\u0433\u043E] \u043E\u0431\u0435\u0442 <em>(vratam)</em>, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0444\u043E\u0440\u043C\u0443 \u0438\u0437-\u0437\u0430 \u0435\u0433\u043E \u0431\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F \u043A \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0443; \u044D\u0442\u043E \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435 \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u0432\u044B\u0439 \u043F\u043E\u0441\u0442\u0443\u043F\u043E\u043A \u0441 \u0435\u0433\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u044B]||26||</strong></p></blockquote><p>\u0412 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0442\u043E\u0447\u043A\u043E\u0439 \u0437\u0440\u0435\u043D\u0438\u044F <em>(d\u1E5B\u015B\u0101)</em>, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439 [\u0440\u0430\u043D\u0435\u0435] <em>(prokta)</em> \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E Yog\u012B <em>(yogina\u1E25)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0433\u043E <em>(tulyasya)</em> \u015Aiva <em>(\u015Biva)</em> [\u0438] \u0436\u0438\u0432\u0443\u0449\u0435\u0433\u043E <em>(vartam\u0101nasya)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(bh\u0101vena)</em> &quot;\u042F <em>(aham)</em> [\u0435\u0441\u0442\u044C] \u015Aiva <em>(\u015Biva)</em>&quot;, [\u0438 \u043D\u0430\u0437\u0432\u0430\u043D\u043D\u043E\u0433\u043E] <em>(yad)</em> \u043E\u0441\u0442\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(v\u1E5Btti\u1E25)</em> [\u0438\u043B\u0438] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C <em>(vartanam)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(\u015Bar\u012Bre)</em>, \u0442\u043E \u044D\u0442\u043E [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tad eva)</em> [\u0435\u0433\u043E] \u043E\u0431\u0435\u0442\u043E\u043C <em>(vratam)</em>. [\u041F\u043E\u044D\u0442\u043E\u043C\u0443,] \u0432 [\u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u043C] \u0441\u043B\u0443\u0447\u0430\u0435 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u0435\u0434\u0430\u043D <em>(tatparasya)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044E <em>(p\u016Bj\u0101)</em> \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u043C\u0443 <em>(nitya-udita)</em> \u0412\u044B\u0441\u0448\u0435\u043C\u0443 [\u042F] <em>(para)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(\u0101tmaka)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>, [\u0442\u0430\u043A\u043E\u0439 \u043E\u0431\u0435\u0442] \u0441\u043E\u0431\u043B\u044E\u0434\u0430\u0435\u0442\u0441\u044F <em>(anu\u1E63\u1E6Dheyam)</em> \u043A\u0430\u043A \u0430\u043A\u0442 \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u044F <em>(niyamena)</em>|</p><p>\u0422\u0430\u043A [\u0431\u044B\u043B\u043E] <em>(tath\u0101 ca)</em> [\u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E] \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em> [\u0442\u0430\u043A\u0436\u0435]:</p><blockquote><p>&quot;\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A <em>(yath\u0101)</em> \u0432 \u0445\u043E\u0440\u043E\u0448\u043E \u0440\u0430\u0437\u0433\u043E\u0440\u0435\u0432\u0448\u0435\u043C\u0441\u044F \u043A\u043E\u0441\u0442\u0440\u0435 <em>(su-prad\u012Bpte... vahnau)</em> \u043F\u043B\u0430\u043C\u044F <em>(\u015Bikh\u0101)</em> \u0432\u0438\u0434\u043D\u043E <em>(d\u1E5B\u015Byeta ca)</em> \u0432 \u043D\u0435\u0431\u0435 <em>(ambare)</em>, \u0442\u0430\u043A\u0436\u0435 \u0438 <em>(tad-vat)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C <em>(\u0101tm\u0101)</em>, [\u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430] \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E\u0435 <em>(hi)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(sthita\u1E25)</em> \u0432 \u0442\u0435\u043B\u0435 \u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(deha-pr\u0101\u1E47a)</em>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u043D\u043E\u0439 <em>(l\u012Byeta)</em> \u0432 \u0415\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(tad-pade... iti)</em> --\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u015Aiva--<sup>2</sup>&quot;||<br> [\u0421\u043C. IV, 398 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E [\u0432 \u0441\u0442\u0440\u043E\u0444\u0435 Svacchandatantra] <em>(ukty\u0101)</em>, \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0430\u0435\u0442\u0441\u044F, \u0447\u0442\u043E <em>(uktam)</em> \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0435 <em>(sam\u0101vi\u1E63\u1E6Datvam)</em> \u015Aiva <em>(bhavati)</em> \u0432 [Yog\u012B], \u043A\u043E\u0442\u043E\u0440\u044B\u0439 [\u0435\u0449\u0435] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(avasthitasya eva)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(deha)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> --\u0445\u043E\u0442\u044F \u043E\u043D \u0432\u0441\u0435 \u0435\u0449\u0435 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u0435\u043B\u0435, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0438 \u043F\u0440., \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043B\u0438\u0442 \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C!--|</p><p>\u041D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u0434\u0440\u0443\u0433\u043E\u0433\u043E <em>(na punar)</em> \u043E\u0431\u0435\u0442\u0430 <em>(vratam)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u043B\u0441\u044F \u0431\u044B \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(upayuktam)</em> \u0434\u043B\u044F \u043D\u0435\u0433\u043E <em>(tasya)</em>,</p><p>\u043A\u0440\u043E\u043C\u0435 <em>(vyatiriktam)</em> \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F <em>(sthiti)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> [\u0431\u044B\u043B\u043E] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Trikas\u0101ra <em>(\u015Br\u012B-trikas\u0101re)</em>:</p><blockquote><p>&quot;\u0422\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043C\u0443\u0434\u0440 <em>(budha\u1E25)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0442\u043C\u0435\u0447\u0435\u043D <em>(sad\u0101 mudrita\u1E25)</em> Mudr\u0101-s --\u0417\u0430\u043C\u043A\u0430\u043C\u0438-- <em>(mudr\u0101bhi\u1E25)</em><sup>3</sup>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u043C\u0438 <em>(utthit\u0101bhi\u1E25)</em> \u0438\u0437 \u0442\u0435\u043B\u0430 <em>(deha)</em>. \u041E\u043D \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 <em>(sa\u1E25 tu)</em>, \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(prokta\u1E25)</em> \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u0435\u043C <em>(dhara\u1E25)</em> Mudr\u0101-s <em>(mudr\u0101)</em>. \u041E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 <em>(\u015Be\u1E63\u0101\u1E25)</em>, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F <em>(vai)</em>, \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0434\u0435\u0440\u0436\u0430\u0442\u0435\u043B\u044F\u043C\u0438 <em>(dh\u0101rak\u0101\u1E25)</em> \u043A\u043E\u0441\u0442\u0435\u0439 <em>(asthi... iti)</em>&quot;||</p></blockquote><p>\u0412 \u0434\u0440\u0430\u0433\u043E\u0446\u0435\u043D\u043D\u043E\u0439 Kulapa\xF1c\u0101\u015Bik\u0101 <em>(\u015Br\u012B-kulapa\xF1c\u0101\u015Bik\u0101y\u0101m)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>, [\u0431\u044B\u043B\u043E \u0443\u043A\u0430\u0437\u0430\u043D\u043E, \u0447\u0442\u043E]:</p><blockquote><p>&quot;\u0423\u0432\u0438\u0434\u0435\u0432 <em>(d\u1E5B\u1E63\u1E6Dv\u0101)</em> \u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E, \u043A\u0442\u043E \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u043E\u0449\u0443\u0442\u0438\u043C\u044B\u0445 [\u0440\u0435\u043B\u0438\u0433\u0438\u043E\u0437\u043D\u044B\u0445] \u0437\u043D\u0430\u043A\u043E\u0432 <em>(a-vyakta-li\u1E45ginam)</em>, Mar\u012Bci-s --\u0412\u044B\u0441\u0448\u0438\u0435 \u0421\u0438\u043B\u044B-- <em>(mar\u012Bcaya\u1E25)</em> \u043E\u0431\u0449\u0430\u044E\u0442\u0441\u044F <em>(sambh\u0101\u1E63ante)</em> [\u0441 \u043D\u0438\u043C]. \u041E\u043D\u0438 \u043D\u0435 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0442\u0441\u044F \u0441 <em>(na upasarpanti)</em> \u0442\u0435\u043C, \u043A\u0442\u043E \u0438\u043C\u0435\u0435\u0442 [\u0440\u0435\u043B\u0438\u0433\u0438\u043E\u0437\u043D\u044B\u0435] \u0437\u043D\u0430\u043A\u0438*(li\u1E45ginam)*, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> [\u044D\u0442\u0438 \u0412\u044B\u0441\u0448\u0438\u0435 \u0421\u0438\u043B\u044B] \u2014 \u043E\u0447\u0435\u043D\u044C \u0442\u0430\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0438 \u043D\u0435\u043F\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u044B\u0435 <em>(atiguptatar\u0101\u1E25... iti)</em>&quot;||</p></blockquote><p>||26||</p><hr><ol><li><p>\u041F\u043E\u0437\u0432\u043E\u043B\u044C\u0442\u0435 \u043C\u043D\u0435 \u0431\u043E\u043B\u0435\u0435 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435: &quot;\xFApanata&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0432\u044B\u043F\u0430\u0432\u0448\u0438\u0439 \u043D\u0430 \u0447\u044C\u044E-\u0442\u043E \u0434\u043E\u043B\u044E&quot;, &quot;bhoga&quot; \u2014 \u044D\u0442\u043E &quot;\u043E\u0431\u044A\u0435\u043A\u0442 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F&quot; \u0438 &quot;ativ\u0101hana&quot; \u0435\u0441\u0442\u044C &quot;\u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442\u044C&quot;. \u0421\u043B\u043E\u0432\u043E\u043C, &quot;\u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0432\u044B\u043F\u0430\u0434\u0430\u0442\u044C \u043D\u0430 \u0435\u0433\u043E \u0434\u043E\u043B\u044E&quot;, \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 &quot;\u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0442\u044C\u0441\u044F \u044D\u0442\u0438\u043C\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0442, \u0438 \u0437\u0430\u0442\u0435\u043C \u043E\u0442\u043F\u0443\u0441\u043A\u0430\u0442\u044C \u0438\u0445&quot;. \u0412 \u044D\u0442\u043E\u043C \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043D\u0435\u0442 \u043D\u0438 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438, \u043D\u0438 \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u044F. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u043C\u0443\u0434\u0440\u0435\u0446 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E \u0432\u0435\u043B\u0438\u043A\u043E\u043C Yog\u012B, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u043B\u0443\u0447\u0438\u043B \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438. \u041F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u0441\u0442\u0440\u0435\u043C\u044F\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043A \u0431\u043E\u043B\u044C\u0448\u0435\u043C\u0443 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0443 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u0447\u0435\u043C \u0442\u0435, \u0447\u0442\u043E &quot;\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E&quot; \u0432\u044B\u043F\u0430\u0434\u0430\u044E\u0442 \u043D\u0430 \u0438\u0445 \u0434\u043E\u043B\u044E. \u0411\u043E\u043B\u0435\u0435 \u0442\u043E\u0433\u043E, \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043E\u043D\u0438 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u044E\u0442 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0438 \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435. \u0412\u0441\u0435 \u044D\u0442\u043E \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u043D\u0435 \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u0438\u043C \u043D\u0438\u0447\u0435\u0433\u043E, \u043A\u0440\u043E\u043C\u0435 \u0431\u0435\u0437\u043C\u0435\u0440\u043D\u044B\u0445 \u0433\u043E\u0440\u044F \u0438 \u0431\u043E\u043B\u0438. \u041D\u0443, \u0432\u044B, \u043D\u0430\u0432\u0435\u0440\u043D\u043E, \u0437\u043D\u0430\u0435\u0442\u0435 \u044D\u0442\u0443 \u0438\u0441\u0442\u043E\u0440\u0438\u044E, \u0445\u0435-\u0445\u0435.</p></li><li><p>\u0412\u0435\u0441\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 K\u1E63emar\u0101ja \u043D\u0430 \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 \u0435\u0433\u043E Svacchandoddyota \u0433\u043B\u0430\u0441\u0438\u0442:</p><p>&quot;\u0926\u0947\u0939\u092E\u0928\u094D\u0924\u094D\u0930\u092A\u094D\u0930\u093E\u0923\u093E\u0924\u094D\u092E\u0936\u093F\u0935\u092A\u0926\u093E\u0928\u093E\u092E\u094C\u091A\u093F\u0924\u094D\u092F\u093E\u0924\u094D \u0915\u093E\u0937\u094D\u0920\u093E\u0930\u0923\u093F\u0935\u0939\u094D\u0928\u093F\u0924\u091A\u094D\u091B\u093F\u0916\u093E\u092E\u094D\u092C\u0930\u093E\u0923\u093F \u0926\u0943\u0937\u094D\u091F\u093E\u0928\u094D\u0924\u0903\u0964 \u0924\u0947\u0928\u093E\u0930\u0923\u093F\u092E\u0928\u094D\u0925\u0928\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0938\u0941\u092A\u094D\u0930\u0926\u0940\u092A\u094D\u0924\u0947 \u092A\u094D\u0930\u091C\u094D\u0935\u0932\u093F\u0924\u0947 \u0935\u0939\u094D\u0928\u094C \u0938\u0924\u093F \u092F\u0925\u093E \u0936\u093F\u0916\u093E \u091C\u094D\u0935\u093E\u0932\u093E \u0926\u093E\u0939\u094D\u092F\u0902 \u0926\u0917\u094D\u0927\u094D\u0935\u093E\u092E\u094D\u092C\u0930\u0947 \u0926\u0943\u0936\u094D\u092F\u0924\u0947 \u0924\u0924\u094D\u0930 \u0932\u092F\u093E\u0924\u094D \u0924\u0926\u093E\u0924\u094D\u092E\u092D\u093E\u0935\u0902 \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093E\u0935\u0932\u094B\u0915\u094D\u092F\u0924\u0947 \u0924\u0926\u094D\u0935\u0926\u094D\u0926\u093F\u0935\u094D\u092F\u0915\u0930\u0923\u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0930\u0923\u093F\u0938\u092E\u0941\u0924\u094D\u0924\u0947\u091C\u0928\u0947\u0928 \u0926\u0947\u0939\u0947 \u092F\u0903 \u092A\u094D\u0930\u093E\u0923\u0938\u094D\u0924\u0938\u094D\u092E\u093F\u0928\u094D \u0938\u0941\u092A\u094D\u0930\u0926\u0940\u092A\u094D\u0924\u0947 \u092E\u0927\u094D\u092F\u094B\u0930\u094D\u0927\u094D\u0935\u0935\u093E\u0939\u094D\u092F\u0941\u0926\u093E\u0928\u093E\u0917\u094D\u0928\u093F\u0924\u093E\u092E\u093E\u092F\u093E\u0924\u093F \u0926\u0947\u0939\u0947 \u0938\u094D\u0925\u093F\u0924\u094B \u092F \u0906\u0924\u094D\u092E\u093E \u092A\u094D\u0930\u094B\u0915\u094D\u0924 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u0915\u0947\u0935\u0932\u0930\u0942\u092A\u094B \u0935\u0939\u094D\u0928\u093F\u0936\u093F\u0916\u093E\u0924\u0941\u0932\u094D\u092F\u0903 \u0938\u092E\u0928\u093E\u0928\u094D\u0924\u0902 \u0938\u092E\u0938\u094D\u0924\u0902 \u0926\u0947\u0939\u0926\u093E\u0930\u0941\u0902 \u0926\u0918\u094D\u0926\u094D\u0935\u093E \u0924\u0938\u094D\u092E\u093F\u0928\u094D\u092A\u0926\u0947 \u0932\u0940\u092F\u0924\u0947 \u0928\u093F\u0930\u0941\u092A\u093E\u0927\u093F\u092A\u0930\u092E\u0936\u093F\u0935\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u092E\u0947\u0924\u094D\u092F\u0947\u0935\u0947\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0965\u0969\u096F\u096E\u0965&quot;</p><p>&quot;Dehamantrapr\u0101\u1E47\u0101tma\u015Bivapad\u0101n\u0101maucity\u0101t k\u0101\u1E63\u1E6Dh\u0101ra\u1E47ivahnitacchikh\u0101mbar\u0101\u1E47i d\u1E5B\u1E63\u1E6D\u0101nta\u1E25| Ten\u0101ra\u1E47imanthanayukty\u0101 suprad\u012Bpte prajvalite vahnau sati yath\u0101 \u015Bikh\u0101 jv\u0101l\u0101 d\u0101hya\u1E41 dagdhv\u0101mbare d\u1E5B\u015Byate tatra lay\u0101t tad\u0101tmabh\u0101va\u1E41 pr\u0101pt\u0101valokyate tadvaddivyakara\u1E47amantr\u0101ra\u1E47isamuttejanena dehe ya\u1E25 pr\u0101\u1E47astasmin suprad\u012Bpte madhyordhvav\u0101hyud\u0101n\u0101gnit\u0101m\u0101y\u0101ti dehe sthito ya \u0101tm\u0101 prokta \u015Buddhavij\xF1\u0101nakevalar\u016Bpo vahni\u015Bikh\u0101tulya\u1E25 saman\u0101nta\u1E41 samasta\u1E41 dehad\u0101ru\u1E41 daghdv\u0101 tasminpade l\u012Byate nirup\u0101dhiparama\u015Bivaik\u0101tmyametyevetyartha\u1E25||398||&quot;</p><p>&quot;\u0414\u043B\u044F \u0443\u0434\u043E\u0431\u0441\u0442\u0432\u0430, \u0431\u044B\u043B\u043E \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u0434\u0435\u0440\u0435\u0432\u043E\u043C, [\u0434\u0432\u0443\u043C\u044F] \u043A\u0443\u0441\u043A\u0430\u043C\u0438 \u0434\u0435\u0440\u0435\u0432\u0430, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u044B\u043C\u0438 \u0434\u043B\u044F \u0440\u0430\u0437\u0436\u0438\u0433\u0430\u043D\u0438\u044F \u043E\u0433\u043D\u044F \u0442\u0440\u0435\u043D\u0438\u0435\u043C, \u043E\u0433\u043D\u0435\u043C, \u0435\u0433\u043E \u043F\u043B\u0430\u043C\u0435\u043D\u0435\u043C --\u0442.\u0435. \u043F\u043B\u0430\u043C\u0435\u043D\u0435\u043C \u043E\u0442 \u043E\u0433\u043D\u044F--\u043D\u0435\u0431\u043E\u043C \u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0442\u0435\u043B\u0430, \u043C\u0430\u043D\u0442\u0440\u043E\u0439, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439, \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E \u0438 \u015Aiva (\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E) --\u043A\u043E\u0440\u043E\u0447\u0435, \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u044F \u0442\u0430\u043A\u043E\u0432\u0430: &#39;\u0434\u0435\u0440\u0435\u0432\u043E - \u0442\u0435\u043B\u043E&#39;, &#39;[\u0434\u0432\u0430] \u043A\u0443\u0441\u043A\u0430 \u0434\u0435\u0440\u0435\u0432\u0430 \u0434\u043B\u044F \u0440\u0430\u0437\u0436\u0438\u0433\u0430\u043D\u0438\u044F \u043E\u0433\u043D\u044F \u0442\u0440\u0435\u043D\u0438\u0435\u043C - \u043C\u0430\u043D\u0442\u0440\u0430&#39;, &#39;\u043E\u0433\u043E\u043D\u044C - \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F&#39;, &#39;\u043F\u043B\u0430\u043C\u044F - \u0421\u0430\u043C\u043E\u0441\u0442\u044C&#39; \u0438 &#39;\u043D\u0435\u0431\u043E - \u015Aiva&#39;--. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u043E\u0433\u0434\u0430 \u0435\u0441\u0442\u044C \u0445\u043E\u0440\u043E\u0448\u043E \u0440\u0430\u0437\u043E\u0436\u0436\u0435\u043D\u043D\u044B\u0439, \u0438\u043B\u0438 \u0437\u0430\u0436\u0436\u0435\u043D\u043D\u044B\u0439 \u043E\u0433\u043E\u043D\u044C, \u015Bikh\u0101, \u0438\u043B\u0438 \u043F\u043B\u0430\u043C\u044F, \u0441\u0436\u0438\u0433\u0430\u044E\u0449\u0435\u0435 \u0442\u043E\u043F\u043B\u0438\u0432\u043E \u0445\u043E\u0440\u043E\u0448\u043E \u0432\u0438\u0434\u043D\u043E \u0432 \u043D\u0435\u0431\u0435, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E [\u0442\u0430\u043A\u043E\u0435 \u043F\u043B\u0430\u043C\u044F], \u043F\u043E \u0432\u0438\u0434\u0438\u043C\u043E\u043C\u0443, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0441\u0432\u043E\u0435\u0439 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B, \u0441\u043B\u0438\u0432\u0430\u044F\u0441\u044C \u0441 \u044D\u0442\u0438\u043C --\u0441 \u043D\u0435\u0431\u043E\u043C--, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0432 \u0442\u0435\u043B\u0435, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u0445\u043E\u0440\u043E\u0448\u043E \u0440\u0430\u0437\u0436\u0438\u0433\u0430\u0435\u0442\u0441\u044F, \u0431\u0443\u0434\u0443\u0447\u0438 \u0441\u0438\u043B\u044C\u043D\u043E \u0432\u043E\u0441\u043F\u043B\u0430\u043C\u0435\u043D\u0435\u043D\u043D\u043E\u0439 [\u0434\u0432\u0443\u043C\u044F] \u043A\u0443\u0441\u043A\u0430\u043C\u0438 \u0434\u0435\u0440\u0435\u0432\u0430 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043C\u0430\u043D\u0442\u0440\u044B \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u0432\u0443\u043A\u0430, \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 \u043E\u0433\u043E\u043D\u044C ud\u0101na, \u0442\u0435\u043A\u0443\u0449\u0438\u0439 \u0432\u0432\u0435\u0440\u0445 \u0447\u0435\u0440\u0435\u0437 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u043D\u044B\u0439 \u043A\u0430\u043D\u0430\u043B --\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 Su\u1E63umn\u0101. \u0413\u043E\u0432\u043E\u0440\u044F\u0442, \u0447\u0442\u043E \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 [\u0442\u0430\u043A\u0436\u0435] \u0432 \u0442\u0435\u043B\u0435. \u041E\u043D \u043F\u043E\u0434\u043E\u0431\u0435\u043D \u043F\u043B\u0430\u043C\u0435\u043D\u0438 \u043E\u0433\u043D\u044F. \u0421\u0436\u0438\u0433\u0430\u044F \u0432\u0441\u044E \u0434\u0440\u0435\u0432\u0435\u0441\u0438\u043D\u0443, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0443\u044E \u043A\u0430\u043A \u0442\u0435\u043B\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 Saman\u0101, [\u044D\u0442\u0430 \u0421\u0430\u043C\u043E\u0441\u0442\u044C] \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F \u0441 \u044D\u0442\u0438\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C, \u0442.\u0435. \u041E\u043D, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 Nirup\u0101dhiparama\u015Biva, \u0438\u043B\u0438 Parama\u015Biva \u0431\u0435\u0437 \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u043E\u0432. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.&quot;</p></li><li><p>\u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0442\u0435\u0440\u043C\u0438\u043D Mudr\u0101 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u0417\u0430\u043C\u043A\u0430\u043C, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u043C\u044B\u043C \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0442\u0435\u043B\u0430 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0440\u0443\u043A\u0430\u043C\u0438), \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u0432\u0441\u0435\u043C \u0442\u0435\u043B\u043E\u043C. \u0412\u044B, \u043D\u0430\u0432\u0435\u0440\u043D\u043E, \u0441\u043B\u044B\u0448\u0438\u0442\u0435 \u043E\u0442 \u043C\u043D\u043E\u0433\u0438\u0445 \u043B\u044E\u0434\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0433\u043E\u0432\u043E\u0440\u044F\u0442 (\u0438 \u0434\u0430\u0436\u0435 \u043F\u0438\u0448\u0443\u0442) \u043E \u0419\u043E\u0433\u0435, \u0447\u0442\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 Mudr\u0101 \u0435\u0441\u0442\u044C \u0417\u0430\u043C\u043E\u043A, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D, \u043F\u043E \u0432\u0438\u0434\u0438\u043C\u043E\u043C\u0443, \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u0435\u0442/\u0437\u0430\u043F\u0435\u0447\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0446\u0435\u043F\u044C \u0432 \u0432\u0430\u0448\u0435\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u0435 \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E\u0431\u044B \u044D\u043D\u0435\u0440\u0433\u0438\u044F \u043D\u0435 \u0432\u044B\u0448\u043B\u0430 \u0438 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0431\u044B\u043B\u0430 \u0431\u044B \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0430 \u0432\u043D\u0443\u0442\u0440\u0438. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u044D\u0442\u043E \u0445\u043E\u0440\u043E\u0448\u0438\u0439 \u043F\u0440\u0438\u043C\u0435\u0440 \u0442\u043E\u0433\u043E, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u044B\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u044E \u043C\u043D\u0435\u043D\u0438\u0435, \u0447\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u044B \u0419\u043E\u0433\u0438 \u0438 \u0443\u0447\u0435\u043D\u044B\u0435 \u043C\u043E\u0433\u0443\u0442 \u0441\u043A\u0430\u0437\u0430\u0442\u044C \u0447\u0442\u043E-\u0442\u043E, \u0447\u0442\u043E \u0441\u0442\u043E\u0438\u0442 \u0443\u0441\u043B\u044B\u0448\u0430\u0442\u044C. \u0412\u043E-\u043F\u0435\u0440\u0432\u044B\u0445, \u044D\u043D\u0435\u0440\u0433\u0438\u044F \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043A\u0438\u043D\u0443\u0442\u044C \u0442\u0435\u043B\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043D\u0435\u0442 \u043D\u0438 &quot;\u0441\u043D\u0430\u0440\u0443\u0436\u0438&quot; \u043D\u0438 &quot;\u0432\u043D\u0443\u0442\u0440\u0438&quot; \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u015Aakti. \u042D\u0442\u043E \u0441\u043B\u043E\u0436\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u044C \u0434\u043B\u044F \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u044B, \u0447\u0442\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u043E\u0442\u043B\u0438\u0447\u043D\u0430\u044F \u043E\u0442 \u043D\u0438\u0445 \u0441\u0430\u043C\u0438\u0445, \u0438 \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u043E \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043C\u0438\u0440\u0441\u043A\u0438\u0435, \u043D\u043E \u043B\u044E\u0431\u043E\u0439 \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u044C, \u0438\u043C\u0435\u044E\u0449\u0438\u0439 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0439 \u043E\u043F\u044B\u0442 \u0432 \u0419\u043E\u0433\u0435, \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u044C \u043C\u0435\u043D\u044F. \u0415\u0441\u043B\u0438 \u043A\u0442\u043E-\u0442\u043E, \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0439 \u0419\u043E\u0433\u0443 \u0432\u0441\u0435 \u0435\u0449\u0435 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043D\u044F\u0442\u044C \u043C\u0435\u043D\u044F, \u043D\u0443 \u0442\u043E\u0433\u0434\u0430 \u043E\u043D \u0438\u043B\u0438 \u043E\u043D\u0430 \u2014 \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0437\u0440\u0435\u043B\u044B\u0435 \u0441 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F.</p><p>\u0418\u0442\u0430\u043A, \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0441\u0442\u0440\u0430\u0445\u0430 &quot;\u043F\u043E\u0442\u0435\u0440\u0438&quot; \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0441\u0438\u0441\u0442\u0435\u043C\u0430 &quot;\u043E\u0442\u043A\u0440\u044B\u0442\u0430&quot;. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u043F\u043E\u043D\u044F\u0442\u0438\u0435 &quot;\u044D\u043D\u0435\u0440\u0433\u0438\u0438&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u0436\u0435 \u0432\u0435\u0441\u044C\u043C\u0430 \u043A\u0430\u0432\u0435\u0440\u0437\u043D\u044B\u043C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u2014 \u044D\u0442\u043E &quot;\u0441\u0438\u043B\u0430&quot; (\u015Aakti). \u015Aakti \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u015Aiva (\u0412\u0430\u043C!) \u0438 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0442\u0435\u0440\u044F\u043D\u0430 \u043D\u0438\u043A\u043E\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C. \u042D\u0442\u043E \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C M\u0101y\u0101, \u0438\u043B\u0438 \u041D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043E, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0432\u0430\u0441 \u043F\u043E\u0432\u0435\u0440\u0438\u0442\u044C, \u0447\u0442\u043E \u015Aakti \u043C\u043E\u0436\u0435\u0442 \u0432\u044B\u0439\u0442\u0438 \u0438\u0437 \u0441\u0438\u0441\u0442\u0435\u043C\u044B, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u043E\u0442\u043A\u0440\u044B\u0442\u0430. \u041E \u0411\u043E\u0436\u0435! \u042F \u0441\u0430\u043C \u0433\u043E\u0434\u0430\u043C\u0438 \u0441\u043B\u044B\u0448\u0430\u043B \u044D\u0442\u0443 \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u0443\u044E \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044E &quot;Mudr\u0101-s, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u0442\u043E\u043C\u0443, \u0447\u0442\u043E\u0431\u044B \u015Aakti \u0432\u044B\u0440\u0432\u0430\u043B\u0430\u0441\u044C \u0438\u0437 \u0441\u0438\u0441\u0442\u0435\u043C\u044B&quot;, \u0445\u0435-\u0445\u0435, \u0434\u0430, \u043C\u043E\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F M\u0101y\u0101, \u043A\u043E\u043D\u0435\u0447\u043D\u043E!</p><p>\u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0447\u0442\u043E\u0431\u044B \u0443\u0441\u0442\u0440\u0430\u043D\u0438\u0442\u044C \u044D\u0442\u0443 \u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044E, \u044F \u043C\u043E\u0433\u0443 \u0441\u043A\u0430\u0437\u0430\u0442\u044C \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435: \u0420\u0435\u0430\u043B\u044C\u043D\u0430\u044F \u0446\u0435\u043B\u044C Mudr\u0101 \u2014 \u044D\u0442\u043E \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0443\u043C \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C\u0441\u044F \u0441 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044D\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;\u0417\u0430\u043C\u043E\u043A&quot;. \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0435 \u0438\u0437 \u0440\u0430\u0437\u043D\u044B\u0445 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432, \u043D\u043E \u0442\u043E (\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435), \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F \u0434\u0430\u043B \u0432\u0430\u043C, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u043C \u0432 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u043C \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0435 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u043E\u0432. \u0418, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u043D\u0438\u043A\u0442\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C &quot;\u043F\u043E\u0434\u043B\u0438\u043D\u043D\u044B\u0435&quot; Mudr\u0101-s \u043F\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0436\u0435\u043B\u0430\u043D\u0438\u044E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u0447\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u0435\u043C Mudr\u0101-s, \u0442\u043E\u0433\u0434\u0430 \u043A\u0430\u043A \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u0435 \u044D\u0442\u0438 \u0417\u0430\u043C\u043A\u0438, \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0438 \u043A\u043E\u0441\u0442\u0438.</p></li></ol></div>',2),r=[o];function p(u,s,v,d,n,h){return t(),e("div",null,r)}var l=a(i,[["render",p]]);export{k as __pageData,l as default};
